<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1.0"/>
  <title>Ubuntu Desktop Clone</title>
  <style>
    * { box-sizing: border-box; }
    body {
      margin: 0;
      background-color: #2e3436;
      font-family: sans-serif;
    }
    #desktop {
      position: relative;
      width: 100vw;
      height: 100vh;
    }
    #taskbar {
      position: fixed;
      top: 0; left: 0; right: 0;
      height: 40px;
      background-color: #2e3436;
      display: flex;
      align-items: center;
      padding: 10px;
    }
    button {
      margin-right: 10px;
      cursor: pointer;
    }
    .window {
      position: absolute;
      top: 80px; left: 50%;
      width: 420px;
      min-width: 360px;
      min-height: 240px;
      background-color: white;
      border: 1px solid #ccc;
      box-shadow: 0 0 10px rgba(0,0,0,0.2);
      transform: translateX(-50%);
    }
    .win-title {
      cursor: move;
      padding: 5px 10px;
      background-color: #4c4f69;
      color: white;
    }
    .win-close {
      float: right;
      font-weight: bold;
      cursor: pointer;
    }
    .hidden { display: none; }
    #files-path {
      padding: 5px;
      border-bottom: 1px solid #ccc;
    }
    ul.fs-list {
      list-style-type: none;
      margin: 0; padding: 0;
      max-height: calc(100% - 80px);
      overflow-y: auto;
    }
    .fs-item {
      padding: 5px;
      border-bottom: 1px solid #eee;
      cursor: pointer;
    }
    .tab {
      display: inline-block;
      margin-right: 5px;
      padding: 5px 10px;
      background-color: #ddd;
      cursor: pointer;
    }
    .tab.active { background-color: white; font-weight: bold; }
    #editor {
      width: 100%;
      height: calc(100% - 60px);
      display: block;
      resize: none;
      padding: 5px;
      box-sizing: border-box;
    }
  </style>
</head>
<body>
<div id="desktop">
  <div id="taskbar">
    <button id="open-files">Files</button>
    <button id="open-notepad">Notepad</button>
  </div>

  <!-- Files Window -->
  <div id="files-window" class="window hidden">
    <div class="win-title">Files</div>
    <span class="win-close">&times;</span>
    <div id="files-path">/</div>
    <ul id="file-list" class="fs-list"></ul>
    <button id="files-up">Up</button>
  </div>

  <!-- Notepad Window -->
  <div id="notepad-window" class="window hidden">
    <div class="win-title">Notepad</div>
    <span class="win-close">&times;</span>
    <div id="tabs"></div>
    <button id="new-tab">New Tab</button>
    <textarea id="editor"></textarea>
  </div>
</div>

<script>
// File system structure
const fakeFs = {
  '/': ['bin', 'etc', 'home', 'usr', 'var'],
  '/home': ['user'],
  '/home/user': ['Documents', 'Downloads', 'Pictures', 'file1.txt']
};

// Files App Logic
function updateFileList(path) {
  const items = fakeFs[path] || [];
  const fileList = document.getElementById('file-list');
  fileList.innerHTML = '';
  items.forEach(item => {
    const el = document.createElement('div');
    el.className = 'fs-item';
    el.textContent = item;
    if (fakeFs[`${path}/${item}`]) {
      el.style.fontWeight = 'bold';
    }
    el.addEventListener('dblclick', () => {
      const newPath = `${path}/${item}`;
      if (fakeFs[newPath]) updateFileList(newPath);
    });
    fileList.appendChild(el);
  });
  document.getElementById('files-path').textContent = path;
}

document.getElementById('files-up').addEventListener('click', () => {
  const currentPath = document.getElementById('files-path').textContent;
  if (currentPath === '/') return;
  const parentPath = currentPath.split('/').slice(0, -1).join('/') || '/';
  updateFileList(parentPath);
});

// Notepad App Logic
let tabsDataKey = 'notepad-tabs';

function saveTabs() {
  const tabs = [];
  document.querySelectorAll('.tab').forEach(tab => {
    const id = tab.dataset.id;
    tabs.push({
      id,
      title: tab.textContent,
      content: localStorage.getItem(`notepad-tab-${id}`) || ''
    });
  });
  localStorage.setItem(tabsDataKey, JSON.stringify(tabs));
}

function loadTabs() {
  document.getElementById('tabs').innerHTML = '';
  const saved = localStorage.getItem(tabsDataKey);
  if (!saved) return;
  try {
    const tabs = JSON.parse(saved);
    tabs.forEach(tab => {
      createTabElement(tab.id, tab.title, tab.content);
    });
    if (document.querySelectorAll('.tab').length > 0)
      document.querySelector('.tab').click();
  } catch(e) {}
}

function createTabElement(id, title, content) {
  const tab = document.createElement('div');
  tab.className = 'tab';
  tab.dataset.id = id;
  tab.textContent = title;
  tab.addEventListener('click', () => {
    document.querySelectorAll('.tab').forEach(t => t.classList.remove('active'));
    tab.classList.add('active');
    const savedContent = localStorage.getItem(`notepad-tab-${id}`) || content;
    document.getElementById('editor').value = savedContent;
  });
  document.getElementById('tabs').appendChild(tab);
}

document.getElementById('new-tab').addEventListener('click', () => {
  const id = Date.now();
  createTabElement(id, 'Untitled', '');
  localStorage.setItem(`notepad-tab-${id}`, '');
  tab.classList.add('active');
  document.getElementById('editor').value = '';
});

// Drag functionality
function initDraggable() {
  document.querySelectorAll('.window .win-title').forEach(titleBar => {
    const windowEl = titleBar.closest('.window');

    let isDragging = false;
    let offsetX, offsetY;

    titleBar.addEventListener('mousedown', (e) => {
      isDragging = true;
      offsetX = e.clientX - windowEl.offsetLeft;
      offsetY = e.clientY - windowEl.offsetTop;
    });

    document.addEventListener('mousemove', (e) => {
      if (!isDragging) return;
      const x = e.clientX - offsetX;
      const y = e.clientY - offsetY;
      windowEl.style.left = `${x}px`;
      windowEl.style.top = `${y}px`;
    });

    document.addEventListener('mouseup', () => isDragging = false);
  });
}

// Window controls
document.querySelectorAll('.win-close').forEach(btn => {
  btn.addEventListener('click', function() {
    const win = this.closest('.window');
    if (win) win.classList.add('hidden');
  });
});

// Open windows
document.getElementById('open-files').addEventListener('click', () => {
  document.getElementById('files-window').classList.remove('hidden');
  updateFileList('/');
});
document.getElementById('open-notepad').addEventListener('click', () => {
  const win = document.getElementById('notepad-window');
  win.classList.remove('hidden');
  loadTabs();
});

// Initialize
initDraggable();

// Load notepad tabs on page load
loadTabs();
</script>
</body>
</html>
